    let coefficients = solve_linear_system(&system_matrix, &rhs_array)?;

    let valid_range = (x_first, x_last);

    Ok(InterpolationSpline {
        knots: knots_array,
        coefficients,
        order,
        x_data: x_array,
        y_data: y_array,
        valid_range,
    })
}

