            assert_relative_eq!(row_sum, 1.0, epsilon = 1e-10);
            if (row_sum - 1.0).abs() > 1e-10 {
                panic!("Row {} sum should be 1.0, got {}", i, row_sum);
            }
        }

        println!("✓ All utility functions equivalent to R splines package");
    }
}

