#[test] 
fn test_interpolation_functional_equivalence_with_r() {
    // Verify that our interpolation spline produces the same results as R's interpSpline
    // Note: We use B-spline representation while R uses piecewise polynomials,
    // but both should produce identical interpolating functions
    let x_vals = vec![0.0, 1.0, 2.0, 3.0];
    let y_vals = vec![0.0, 1.0, 8.0, 27.0];
    let order = 4;

    let spline = InterpolationSpline::new(&x_vals, &y_vals, order).unwrap();

    // Test 1: Exact interpolation at data points
    println!("=== Testing exact interpolation at data points ===");
    for (i, (&x, &expected_y)) in x_vals.iter().zip(y_vals.iter()).enumerate() {
        let result = spline.predict(&[x]).unwrap();
        let actual_y = result.y()[0];
        println!("f({}) = {} (expected {})", x, actual_y, expected_y);
        assert_relative_eq!(actual_y, expected_y, epsilon = 1e-12);
    }

    // Test 2: Verify against R's interpSpline at intermediate points
    // These values were computed using R: 
    // spl <- interpSpline(c(0,1,2,3), c(0,1,8,27))
    // predict(spl, c(0.5, 1.5, 2.5))$y
    println!("\n=== Testing intermediate points against R ground truth ===");
    let test_points = vec![
        (0.5, 0.3125),    // R: predict(spl, 0.5)$y = 0.3125
        (1.5, 3.4375),    // R: predict(spl, 1.5)$y = 3.4375  
        (2.5, 15.3125),   // R: predict(spl, 2.5)$y = 15.3125
    ];

    for (x_test, r_expected) in test_points {
        let result = spline.predict(&[x_test]).unwrap();
        let actual = result.y()[0];
        println!("f({}) = {} (R expects {})", x_test, actual, r_expected);
        assert_relative_eq!(actual, r_expected, epsilon = 1e-10);
    }

    // Test 3: Verify derivatives are continuous (smooth interpolation)
    println!("\n=== Testing derivative continuity ===");
    let test_x = 1.5; // Middle of domain
    let h = 1e-8;

    // Numerical derivative
    let f_minus = spline.predict(&[test_x - h]).unwrap().y()[0];
    let f_plus = spline.predict(&[test_x + h]).unwrap().y()[0];
    let numerical_deriv = (f_plus - f_minus) / (2.0 * h);

    // Analytical derivative
    let analytical_deriv = spline.predict_with_deriv(&[test_x], 1).unwrap().y()[0];

    println!("Derivative at x={}: numerical={}, analytical={}", 
             test_x, numerical_deriv, analytical_deriv);
    assert_relative_eq!(numerical_deriv, analytical_deriv, epsilon = 1e-6);

    println!("✓ Interpolation spline functional equivalence with R verified");
}

